// Now read everything in one pass — the three files, the image, and the voice note (already transcribed above).
// I'll send all file ids to system-files and the image id to system-vision in parallel.
const [filesResult, visionResult] = await Promise.all([
  delegate('system-files', 'dispatch', {
    query: 'Summarize these documents and list every concrete fact — names, dates, amounts, line items, park fees, costs, phone numbers, reference numbers, deadlines. I need enough to build a trip app from this.',
    attachmentIds: ['dbd0da7b-2391-40f8-94e1-65ffb710a103', 'd88595e4-2eb0-46ec-a392-4e4621f41921', 'b1d021f9-430b-49d8-8e41-d78a1e5e2819'],
  }) as { ok: boolean; data?: { summary: string; facts: any } },
  delegate('system-vision', 'vision', {
    query: 'Describe this photo in detail — what is in it, the mood, any notable details. This is from Stone Town, Zanzibar, and the user liked it.',
    attachmentIds: ['4672cc38-9ffb-431c-a3f1-4f8b32da519f'],
  }) as { ok: boolean; data?: { description: string } },
]);
